const express=require("express"),cors=require("cors"),fs=require("fs"),path=require("path"),app=express(),PORT=process.env.PORT||5e3,VIEWS_FILE=path.join("/tmp","views.json");app.use(cors({origin:["http://localhost:3000","https://eltriputra4.vercel.app","https://eltri-project.vercel.app"],methods:["GET","POST"],credentials:!0})),app.use(express.json());const readViews=()=>{fs.existsSync(VIEWS_FILE)||fs.writeFileSync(VIEWS_FILE,JSON.stringify({}));const e=fs.readFileSync(VIEWS_FILE,"utf-8");return JSON.parse(e)},writeViews=e=>{fs.writeFileSync(VIEWS_FILE,JSON.stringify(e,null,2))};app.get("/api/views",(e,s)=>{const i=readViews();s.json(i)}),app.get("/api/views/:id",(e,s)=>{const i=readViews(),r=e.params.id;s.json({id:r,views:i[r]||0})}),app.post("/api/views/:id",(e,s)=>{const i=readViews(),r=e.params.id;i[r]=(i[r]||0)+1,writeViews(i),s.json({id:r,views:i[r]})}),app.listen(PORT,()=>{console.log(`✅ Views server running at port ${PORT}`);writeViews({3:1,10:2,11:1,12:1,13:1,14:6,15:4}),console.log("✏️ Database cloud views.json berhasil di-update!")});